function Modal({pages, title, onClose}) {
  const [pg, setPg] = useState(0);
  return (
    <div className="modal-bg" onClick={onClose}>
      <div className="modal-bar" onClick={e=>e.stopPropagation()}>
        <span className="modal-title">{title}</span>
        <div className="modal-nav">
          <button className="modal-btn" onClick={()=>setPg(p=>p-1)} disabled={pg===0}>← Prev</button>
          <span className="modal-pg">{pg+1} / {pages.length}</span>
          <button className="modal-btn" onClick={()=>setPg(p=>p+1)} disabled={pg===pages.length-1}>Next →</button>
          <button className="modal-close" onClick={onClose}>✕ Close</button>
        </div>
      </div>
      <div className="modal-body" onClick={e=>e.stopPropagation()}>
        <img src={pages[pg]} className="modal-img" alt={`Page ${pg+1}`} />
      </div>
    </div>
  );
}

function CredCard({c}) {
  return (
    <div className="cc">
      <div className="cc-inner">
        {c.badge ? <img src={c.badge} alt={c.title} className="cbadge" /> : null}
        <div className="cc-body">
          <div className="cc-ey">{c.eyebrow}</div>
          <div className="cc-title">{c.title}</div>
          {c.issuer && <div className="cc-issuer">{c.issuer}</div>}
          <div className="cc-text">{c.body}</div>
          {(c.brief || c.verify) && (
            <div className="cc-foot">
              {c.brief && <a href={c.brief} target="_blank" rel="noopener noreferrer" className="btn-pdf">↗ {c.pdfLabel}</a>}
              {c.verify && <span className="cc-verify">{c.verify}</span>}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

