function Form({type}) {
  const [done, setDone] = useState(false);
  const [sending, setSending] = useState(false);
  const [fields, setFields] = useState({});
  const endpoint = type==="inquiry"
    ? "https://formspree.io/f/xnjbklbv"
    : "https://formspree.io/f/mjgeqjeo";

  const set = (k) => (e) => setFields(f=>({...f,[k]:e.target.value}));

  const submit = async () => {
    setSending(true);
    try {
      const res = await fetch(endpoint, {
        method:"POST",
        headers:{"Content-Type":"application/json","Accept":"application/json"},
        body:JSON.stringify(fields)
      });
      if (res.ok) setDone(true);
      else setSending(false);
    } catch { setSending(false); }
  };

  if (done) return <div className="fsuccess">{type==="inquiry" ? "Inquiry received. I will review and respond within 5 business days." : "Application received. Applications are reviewed weekly. Every application receives a response."}</div>;

  if (type==="inquiry") return (
    <div>
      <div className="fld"><label>Your Name</label><input type="text" onChange={set("name")} /></div>
      <div className="fld"><label>Email Address</label><input type="email" onChange={set("email")} /></div>
      <div className="fld"><label>Your Business — what you do and who you serve</label><textarea rows={3} onChange={set("business")} /></div>
      <div className="fld"><label>The Problem You Are Trying to Solve</label><textarea rows={3} onChange={set("problem")} /></div>
      <div className="fld"><label>Your Timeline</label><input type="text" onChange={set("timeline")} /></div>
      <div className="fld"><label>How Did You Find This Page?</label><input type="text" onChange={set("source")} /></div>
      <button className="btn-p" disabled={sending} onClick={submit} style={{width:"100%",justifyContent:"center",marginTop:8}}>{sending ? "Sending..." : "Send My Inquiry →"}</button>
      <div className="fnote">Inquiries reviewed within 5 business days. If there is a potential fit, you will receive next steps. If not, you will receive an honest note about why.</div>
    </div>
  );

  return (
    <div>
      <div className="fld"><label>Your Name</label><input type="text" onChange={set("name")} /></div>
      <div className="fld"><label>Email Address</label><input type="email" onChange={set("email")} /></div>
      <div className="fld"><label>Where You Are Right Now</label>
        <select onChange={set("stage")}><option value="">Select one</option><option>Actively applying but not landing clients</option><option>Just landed my first client</option><option>Have clients but income is inconsistent</option><option>Something else</option></select>
      </div>
      <div className="fld"><label>What Specifically Is Not Working Right Now</label><textarea rows={3} onChange={set("problem")} /></div>
      <div className="fld"><label>What Have You Already Tried?</label><textarea rows={2} onChange={set("tried")} /></div>
      <div className="fld"><label>What Does Success Look Like in 90 Days?</label><textarea rows={2} onChange={set("success")} /></div>
      <div className="fld"><label>When Are You Ready to Start?</label><input type="text" onChange={set("timeline")} /></div>
      <button className="btn-p" disabled={sending} onClick={submit} style={{width:"100%",justifyContent:"center",marginTop:8}}>{sending ? "Sending..." : "Submit My Application →"}</button>
      <div className="fnote">Applications reviewed weekly. Maximum two coaching clients at any time. Every application receives a response.</div>
    </div>
  );
}

